export type ViewState = 'HOME' | 'SEARCH' | 'SAVED' | 'LIST' | 'DETAILS' | 'COOKING';

export const APP_NAME = "Kitchen Mode";
export const COUPLE_NAME = "Hi, Alex & Sam";
