        <div className="absolute top-3 left-3 flex gap-2">
            <div className="bg-primary text-background px-3 py-1 rounded-full text-xs font-bold flex items-center gap-1 shadow-lg">
                <Clock size={14} />
                {recipe.totalTime} MINS
